class Solution:
    def minimumLengthEncoding(self, words):
        words = list(set(words))
        trie = {}
        nodes = []
        for w in words:
            cur = trie
            for ch in reversed(w):
                if ch not in cur:
                    cur[ch] = {}
                cur = cur[ch]
            nodes.append((cur, len(w)))
        total = 0
        for node, length in nodes:
            if not node:
                total += length + 1
        return total

