var minimumLengthEncoding = function(words) {
    words = [...new Set(words)];
    const trie = {};
    const nodes = [];
    for (const w of words) {
        let cur = trie;
        for (let i = w.length - 1; i >= 0; i--) {
            const ch = w[i];
            if (!(ch in cur)) cur[ch] = {};
            cur = cur[ch];
        }
        nodes.push([cur, w.length]);
    }
    let total = 0;
    for (const [node, length] of nodes) {
        if (Object.keys(node).length === 0) total += length + 1;
    }
    return total;
};
